import {getData,getAll} from '@/api/family'

const getDefaultState = () => {
    return {
        familyTree:null,
        colors:null,
        family:null
    }
}
const state = getDefaultState()
const mutations = {
    SET_DATA: (state, data) => {
        state.familyTree = data.tree
        state.colors = data.colors
    },
    SET_DATA_ALL: (state, data) => {
        state.family = data
    },
}

const actions = {
    getData({commit},id) {
        return new Promise((resolve, reject) => {
            getData(id).then((rs) => {
                commit('SET_DATA', rs)
                resolve(rs)
            }).catch(error => {
                reject(error)
            })
        })

    },
    getAll({commit}) {
        return new Promise((resolve, reject) => {
            getAll().then((rs) => {
                commit('SET_DATA_ALL', rs)
                resolve(rs)
            }).catch(error => {
                reject(error)
            })
        })

    }
}

export default {
    namespaced: true,
    state,
    mutations,
    actions
}
