const {createClient} = supabase
const base = createClient('https://pmfxqcqvqrhxnxyotyzp.supabase.co', 'sb_publishable_T98PsjOazNXjyak2nXPwDg_ox52NaWg')
export async function  getData(id) {
    const {data} = await base.from('familytree').select().eq('id',id)
    return data[0]
}
export async function  getAll() {
    const {data} = await base.from('familytree').select().order('id', { ascending: false })
    return data
}
